import asyncio
import json
import logging
import secrets
from dataclasses import dataclass, field
from typing import Dict, Optional, Set

import websockets
from websockets.server import WebSocketServerProtocol


logging.basicConfig(level=logging.INFO)


@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str


@dataclass
class Player:
    player_id: str
    name: str
    websocket: Optional[WebSocketServerProtocol] = None
    inventory: Set[str] = field(default_factory=set)
    lock: asyncio.Lock = field(default_factory=asyncio.Lock)


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.sessions: Dict[WebSocketServerProtocol, str] = {}
        self.global_lock = asyncio.Lock()

    async def send(self, websocket: WebSocketServerProtocol, payload: dict):
        try:
            await websocket.send(json.dumps(payload))
        except Exception:
            logging.exception("Failed to send payload")

    async def broadcast_player_update(self, player_id: str):
        player = self.players.get(player_id)
        if not player:
            return
        payload = {
            "type": "player_inventory",
            "player_id": player.player_id,
            "items": [
                {
                    "item_id": item_id,
                    "name": self.items[item_id].name,
                    "owner_id": self.items[item_id].owner_id,
                }
                for item_id in sorted(player.inventory)
                if item_id in self.items
            ],
        }
        websockets_list = [p.websocket for p in self.players.values() if p.websocket is not None]
        await asyncio.gather(*(self.send(ws, payload) for ws in websockets_list), return_exceptions=True)

    async def notify_trade(self, from_player_id: str, to_player_id: str, item_id: str):
        item = self.items.get(item_id)
        payload = {
            "type": "trade_complete",
            "from_player_id": from_player_id,
            "to_player_id": to_player_id,
            "item": {
                "item_id": item_id,
                "name": item.name if item else None,
                "owner_id": item.owner_id if item else None,
            },
        }
        targets = []
        for pid in (from_player_id, to_player_id):
            p = self.players.get(pid)
            if p and p.websocket:
                targets.append(p.websocket)
        await asyncio.gather(*(self.send(ws, payload) for ws in targets), return_exceptions=True)

    async def register_player(self, websocket: WebSocketServerProtocol, data: dict):
        player_id = data.get("player_id") or secrets.token_hex(8)
        name = data.get("name", f"Player-{player_id[:6]}")

        async with self.global_lock:
            if player_id not in self.players:
                self.players[player_id] = Player(player_id=player_id, name=name, websocket=websocket)
                for i in range(3):
                    item_id = secrets.token_hex(6)
                    item = Item(item_id=item_id, name=f"StarterItem{i+1}", owner_id=player_id)
                    self.items[item_id] = item
                    self.players[player_id].inventory.add(item_id)
            else:
                self.players[player_id].websocket = websocket
                self.players[player_id].name = name

            self.sessions[websocket] = player_id

        await self.send(
            websocket,
            {
                "type": "registered",
                "player_id": player_id,
                "name": self.players[player_id].name,
            },
        )
        await self.broadcast_player_update(player_id)

    async def get_state(self, websocket: WebSocketServerProtocol):
        player_id = self.sessions.get(websocket)
        if not player_id:
            await self.send(websocket, {"type": "error", "message": "Not registered"})
            return

        state = {
            "type": "state",
            "you": player_id,
            "players": [
                {
                    "player_id": p.player_id,
                    "name": p.name,
                    "online": p.websocket is not None,
                    "inventory": [
                        {
                            "item_id": item_id,
                            "name": self.items[item_id].name,
                            "owner_id": self.items[item_id].owner_id,
                        }
                        for item_id in sorted(p.inventory)
                        if item_id in self.items
                    ],
                }
                for p in self.players.values()
            ],
        }
        await self.send(websocket, state)

    async def transfer_item(self, websocket: WebSocketServerProtocol, data: dict):
        from_player_id = self.sessions.get(websocket)
        to_player_id = data.get("to_player_id")
        item_id = data.get("item_id")

        if not from_player_id:
            await self.send(websocket, {"type": "error", "message": "Not registered"})
            return
        if not to_player_id or not item_id:
            await self.send(websocket, {"type": "error", "message": "Missing to_player_id or item_id"})
            return
        if to_player_id == from_player_id:
            await self.send(websocket, {"type": "error", "message": "Cannot transfer to self"})
            return

        from_player = self.players.get(from_player_id)
        to_player = self.players.get(to_player_id)
        item = self.items.get(item_id)

        if not from_player or not to_player or not item:
            await self.send(websocket, {"type": "error", "message": "Invalid player or item"})
            return

        first_lock, second_lock = (
            (from_player.lock, to_player.lock)
            if from_player.player_id < to_player.player_id
            else (to_player.lock, from_player.lock)
        )

        async with first_lock:
            async with second_lock:
                if item_id not in from_player.inventory:
                    await self.send(
                        websocket,
                        {"type": "error", "message": "Item not owned by requesting player"},
                    )
                    return

                if item.owner_id != from_player_id:
                    await self.send(
                        websocket,
                        {"type": "error", "message": "Ownership mismatch"},
                    )
                    return

                from_player.inventory.remove(item_id)
                to_player.inventory.add(item_id)
                item.owner_id = to_player_id

        await self.send(
            websocket,
            {
                "type": "transfer_ok",
                "item_id": item_id,
                "from_player_id": from_player_id,
                "to_player_id": to_player_id,
            },
        )
        await asyncio.gather(
            self.broadcast_player_update(from_player_id),
            self.broadcast_player_update(to_player_id),
            self.notify_trade(from_player_id, to_player_id, item_id),
            return_exceptions=True,
        )

    async def create_item(self, websocket: WebSocketServerProtocol, data: dict):
        player_id = self.sessions.get(websocket)
        if not player_id:
            await self.send(websocket, {"type": "error", "message": "Not registered"})
            return

        name = data.get("name", "UnnamedItem")
        player = self.players.get(player_id)
        if not player:
            await self.send(websocket, {"type": "error", "message": "Player not found"})
            return

        item_id = secrets.token_hex(6)
        item = Item(item_id=item_id, name=name, owner_id=player_id)

        async with player.lock:
            self.items[item_id] = item
            player.inventory.add(item_id)

        await self.send(
            websocket,
            {
                "type": "item_created",
                "item": {"item_id": item_id, "name": name, "owner_id": player_id},
            },
        )
        await self.broadcast_player_update(player_id)

    async def unregister(self, websocket: WebSocketServerProtocol):
        player_id = self.sessions.pop(websocket, None)
        if player_id and player_id in self.players:
            self.players[player_id].websocket = None
            logging.info("Player disconnected: %s", player_id)

    async def handle_message(self, websocket: WebSocketServerProtocol, message: str):
        try:
            data = json.loads(message)
        except json.JSONDecodeError:
            await self.send(websocket, {"type": "error", "message": "Invalid JSON"})
            return

        action = data.get("action")
        if action == "register":
            await self.register_player(websocket, data)
        elif action == "state":
            await self.get_state(websocket)
        elif action == "transfer_item":
            await self.transfer_item(websocket, data)
        elif action == "create_item":
            await self.create_item(websocket, data)
        else:
            await self.send(websocket, {"type": "error", "message": f"Unknown action: {action}"})

    async def handler(self, websocket: WebSocketServerProtocol):
        logging.info("Client connected")
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        except websockets.ConnectionClosed:
            pass
        finally:
            await self.unregister(websocket)


async def main():
    server = GameServer()
    async with websockets.serve(server.handler, "0.0.0.0", 8765, max_size=2**20):
        logging.info("MMO server running on ws://0.0.0.0:8765")
        await asyncio.Future()


if __name__ == "__main__":
    asyncio.run(main())